    # 初始化连接池状态（模拟）
    pool_state = {
        "pool_size": pool_size,
        "active_connections": 0,
        "available_connections": pool_size,
        "status": "initialized",
        "health_check_interval": health_check_interval
    }
    return pool_state

def create_db_connection_pool(db_config: dict, pool_config: dict = None) -> dict:
    """
    创建数据库连接池管理器。

    参数:
        db_config (dict): 数据库连接配置，必须包含 host, port, user, password, database。
        pool_config (dict, optional): 连接池配置，可包含 min_size, max_size, timeout, health_check_interval。

    返回:
        dict: 包含 status 和 pool 信息的字典，失败时返回包含 error 字段的字典。
    """
    # 验证 db_config 是否为空或缺少必要字段
    required_db_keys = ['host', 'port', 'user', 'password', 'database']
    if not db_config or not all(key in db_config for key in required_db_keys):
        return {'error': 'Invalid db_config: missing required keys.'}

    # 设置默认 pool_config
    if pool_config is None:
        pool_config = {}
    default_pool_config = {
        'min_size': 2,
        'max_size': 10,
        'timeout': 30,
        'health_check_interval': 60
    }
    # 合并配置，用户提供的覆盖默认值
    merged_config = {**default_pool_config, **pool_config}

    # 验证 pool_config 参数
    min_size = merged_config.get('min_size', 2)
    max_size = merged_config.get('max_size', 10)
    timeout = merged_config.get('timeout', 30)
    health_check_interval = merged_config.get('health_check_interval', 60)

    if not isinstance(min_size, int) or not isinstance(max_size, int):
        return {'error': 'min_size and max_size must be integers.'}
    if min_size < 0 or max_size < 0:
        return {'error': 'min_size and max_size must be non-negative.'}
    if min_size > max_size:
        return {'error': 'min_size cannot be greater than max_size.'}
    if not isinstance(timeout, (int, float)) or timeout <= 0:
        return {'error': 'timeout must be a positive number.'}
    if not isinstance(health_check_interval, (int, float)) or health_check_interval <= 0:
        return {'error': 'health_check_interval must be a positive number.'}

    # 模拟连接池状态（实际实现会创建连接，这里仅返回配置信息）
    pool_status = {
        'min_size': min_size,
        'max_size': max_size,
        'active_connections': 0,
        'idle_connections': min_size,  # 初始空闲连接数等于 min_size
        'waiting_queue_size': 0
    }

    return {
        'status': 'success',
        'pool': pool_status
    }

def distributed_rate_limiter(algorithm: str, rules: dict, key: str, request_info: dict = None) -> dict:
    if not rules:
        return {'error': 'rules cannot be empty'}
    if algorithm not in ['fixed_window', 'sliding_window', 'token_bucket', 'leaky_bucket']:
        return {'error': f'unsupported algorithm: {algorithm}'}
    if request_info is None:
        request_info = {}
    timestamp = request_info.get('timestamp', 0)
    if algorithm == 'fixed_window':
        window_size = rules.get('window_size')
        max_requests = rules.get('max_requests')
        if not window_size or not max_requests:
            return {'error': 'missing window_size or max_requests'}
        window_start = (timestamp // window_size) * window_size
        reset_time = window_start + window_size
        remaining = max_requests - 1
        allowed = remaining >= 0
        return {'allowed': allowed, 'remaining': max(remaining, 0), 'reset_time': reset_time, 'algorithm': algorithm}
    elif algorithm == 'token_bucket':
        capacity = rules.get('capacity')
        refill_rate = rules.get('refill_rate')
        if not capacity or not refill_rate:
            return {'error': 'missing capacity or refill_rate'}
        remaining = capacity - 1
        allowed = remaining >= 0
        return {'allowed': allowed, 'remaining': max(remaining, 0), 'reset_time': None, 'algorithm': algorithm}
    elif algorithm == 'sliding_window':
        window_size = rules.get('window_size')
        max_requests = rules.get('max_requests')
        if not window_size or not max_requests:
            return {'error': 'missing window_size or max_requests'}
        remaining = max_requests - 1
        allowed = remaining >= 0
        reset_time = timestamp + window_size
        return {'allowed': allowed, 'remaining': max(remaining, 0), 'reset_time': reset_time, 'algorithm': algorithm}
    elif algorithm == 'leaky_bucket':
        capacity = rules.get('capacity')
        leak_rate = rules.get('leak_rate')
        if not capacity or not leak_rate:
            return {'error': 'missing capacity or leak_rate'}
        remaining = capacity - 1
        allowed = remaining >= 0
        return {'allowed': allowed, 'remaining': max(remaining, 0), 'reset_time': None, 'algorithm': algorithm}
    return {'error': 'unexpected error'}

def create_http_client(base_url: str, api_key: str = '', timeout: int = 30, max_retries: int = 3, headers: dict = None) -> dict:
    if not isinstance(base_url, str) or not base_url.strip():
        return {'error': 'base_url must be a non-empty string'}
