        return {'error': 'base_url must start with http:// or https://'}
    if not isinstance(api_key, str):
        return {'error': 'api_key must be a string'}
    if not isinstance(timeout, (int, float)) or timeout <= 0:
        return {'error': 'timeout must be a positive number'}
    if not isinstance(max_retries, int) or max_retries < 0:
        return {'error': 'max_retries must be a non-negative integer'}
    if headers is None:
        headers = {}
    if not isinstance(headers, dict):
        return {'error': 'headers must be a dictionary'}
    client = {
        'base_url': base_url,
        'api_key': api_key,
        'timeout': timeout,
        'max_retries': max_retries,
