def create_http_client(base_url: str, api_key: str = None, timeout: int = 30, max_retries: int = 3, headers: dict = None) -> dict:
    """
    Create a configurable HTTP client with retry, timeout, and error handling.

    Args:
        base_url (str): Base URL for the API (required).
        api_key (str, optional): API key for authentication.
        timeout (int, optional): Request timeout in seconds (default 30).
        max_retries (int, optional): Maximum number of retries (default 3).
        headers (dict, optional): Additional headers.

    Returns:
        dict: A dictionary containing the client configuration on success,
              or an error dictionary on failure.
    """
    # Validate base_url
    if not base_url or not isinstance(base_url, str):
        return {"error": "base_url must be a non-empty string"}

    # Validate timeout
    if not isinstance(timeout, (int, float)) or timeout <= 0:
        return {"error": "timeout must be a positive number"}

    # Validate max_retries
    if not isinstance(max_retries, int) or max_retries < 0:
        return {"error": "max_retries must be a non-negative integer"}

    # Validate headers
    if headers is None:
        headers = {}
    elif not isinstance(headers, dict):
        return {"error": "headers must be a dictionary"}

    # Build client configuration
    client_config = {
        "base_url": base_url,
        "api_key": api_key,
        "timeout": timeout,
        "max_retries": max_retries,
        "headers": headers
    }

