    }

def execute_workflow(workflow_definition: dict, initial_data: dict = None) -> dict:
    """
    Execute a workflow based on the definition and initial data.

    Parameters:
    workflow_definition (dict): A dictionary containing nodes and edges defining the workflow.
    initial_data (dict, optional): Initial data to pass to the workflow. Defaults to None.

    Returns:
    dict: A dictionary with status, result, and logs if successful, or an error dictionary if failed.
    """
    logs = []
    try:
        # Validate workflow_definition
        if not isinstance(workflow_definition, dict):
            return {"error": "workflow_definition must be a dictionary"}

        nodes = workflow_definition.get("nodes")
        edges = workflow_definition.get("edges")

        if not nodes or not isinstance(nodes, list):
            return {"error": "Invalid workflow definition: missing or invalid nodes"}

        if edges is None or not isinstance(edges, list):
            return {"error": "Invalid workflow definition: missing or invalid edges"}

        # Build node map
        node_map = {}
        start_node = None
        end_node = None
        for node in nodes:
            if not isinstance(node, dict) or "id" not in node or "type" not in node:
                return {"error": "Invalid node format"}
            node_id = node["id"]
            node_type = node["type"]
            node_map[node_id] = node
            if node_type == "start":
                if start_node is not None:
                    return {"error": "Multiple start nodes found"}
                start_node = node
            elif node_type == "end":
                if end_node is not None:
                    return {"error": "Multiple end nodes found"}
                end_node = node

        if start_node is None:
            return {"error": "No start node found"}
        if end_node is None:
            return {"error": "No end node found"}

        # Build adjacency list for edges
        adjacency = {}
        for edge in edges:
            if not isinstance(edge, dict) or "from" not in edge or "to" not in edge:
                return {"error": "Invalid edge format"}
            from_id = edge["from"]
            to_id = edge["to"]
            if from_id not in node_map or to_id not in node_map:
                return {"error": "Edge references non-existent node"}
            if from_id not in adjacency:
                adjacency[from_id] = []
            adjacency[from_id].append(to_id)

        # Initialize data
        data = initial_data.copy() if initial_data else {}

        # Start execution
        current_node = start_node
        logs.append("Workflow started")

        # Execute until end node
        while current_node["type"] != "end":
            node_id = current_node["id"]
            node_type = current_node["type"]

            if node_type == "task":
                action = current_node.get("action")
                if not action:
                    return {"error": f"Task node {node_id} has no action"}

                # Execute action
                if action == "print_hello":
                    output = "hello"
                else:
                    return {"error": f"Unknown action: {action}"}

                # Store output
                data[f"{node_id}_output"] = output
                logs.append(f"{node_id.capitalize()} executed")

            # Find next node
            if node_id not in adjacency:
                return {"error": f"No outgoing edge from node {node_id}"}

            next_node_ids = adjacency[node_id]
            if len(next_node_ids) != 1:
                return {"error": f"Multiple outgoing edges from node {node_id}, not supported in this implementation"}

            next_node_id = next_node_ids[0]
            current_node = node_map[next_node_id]

        # At end node
        logs.append("Workflow completed")

        return {
            "status": "success",
            "result": data,
            "logs": logs
        }

    except Exception as e:
        return {"error": str(e)}

def execute_workflow(workflow_definition, input_data=None) -> dict:
    """
    Execute a workflow defined by nodes and edges.

    Parameters:
    workflow_definition (dict): A dictionary containing 'nodes' and 'edges' defining the workflow.
    input_data (dict, optional): Initial data to pass to the workflow. Defaults to None.

    Returns:
    dict: A dictionary with 'status', 'output', and 'logs' on success, or 'error' on failure.
    """
    logs = []
    logs.append("Workflow started")

    # Validate workflow_definition
    if not isinstance(workflow_definition, dict):
        return {"error": "Workflow definition must be a dictionary"}

    nodes = workflow_definition.get("nodes")
    edges = workflow_definition.get("edges")

    if nodes is None or edges is None:
        return {"error": "Workflow definition must contain 'nodes' and 'edges'"}

    if not isinstance(nodes, list) or not isinstance(edges, list):
        return {"error": "'nodes' and 'edges' must be lists"}

    # Build node map and adjacency list
    node_map = {}
    for node in nodes:
        if not isinstance(node, dict) or "id" not in node or "type" not in node:
            return {"error": "Invalid node format"}
        node_id = node["id"]
        node_type = node["type"]
        if node_type not in ["start", "end", "task", "condition", "loop"]:
            return {"error": f"Unknown node type: {node_type}"}
        node_map[node_id] = node

    # Check for start and end nodes
    start_nodes = [node for node in nodes if node["type"] == "start"]
    end_nodes = [node for node in nodes if node["type"] == "end"]

    if len(start_nodes) != 1:
        return {"error": "Workflow must have exactly one start node"}
    if len(end_nodes) != 1:
        return {"error": "Workflow must have exactly one end node"}

    start_node = start_nodes[0]
    end_node = end_nodes[0]

    # Build adjacency list
    adjacency = {}
    for edge in edges:
        if not isinstance(edge, dict) or "from" not in edge or "to" not in edge:
            return {"error": "Invalid edge format"}
        from_id = edge["from"]
        to_id = edge["to"]
        if from_id not in node_map or to_id not in node_map:
            return {"error": "Edge references non-existent node"}
        if from_id not in adjacency:
            adjacency[from_id] = []
        adjacency[from_id].append(to_id)

    # Execute workflow
    current_node_id = start_node["id"]
    data = input_data if input_data is not None else {}

    while current_node_id != end_node["id"]:
        current_node = node_map[current_node_id]
        node_type = current_node["type"]

        if node_type == "start":
            # Move to next node
            if current_node_id not in adjacency:
                return {"error": "No outgoing edge from start node"}
            next_nodes = adjacency[current_node_id]
            if len(next_nodes) != 1:
                return {"error": "Start node must have exactly one outgoing edge"}
            current_node_id = next_nodes[0]

        elif node_type == "task":
            action = current_node.get("action")
            if not action:
                return {"error": "Task node must have an 'action' field"}
            logs.append(f"Task {current_node_id} executed")
            # Simulate action execution
            if action == "process_data":
                data = {"result": "processed"}
            else:
                return {"error": f"Unknown action: {action}"}
            # Move to next node
            if current_node_id not in adjacency:
                return {"error": f"No outgoing edge from task node {current_node_id}"}
            next_nodes = adjacency[current_node_id]
            if len(next_nodes) != 1:
                return {"error": f"Task node {current_node_id} must have exactly one outgoing edge for sequential execution"}
            current_node_id = next_nodes[0]

        elif node_type == "condition" or node_type == "loop":
            return {"error": f"Node type {node_type} not implemented"}

        else:
            return {"error": f"Unexpected node type: {node_type}"}

    # Reached end node
    logs.append("Workflow completed")

    return {
        "status": "success",
        "output": data,
        "logs": logs
    }
